K::cmp_properties();
    K::zero_properties();
    let iter = KeyIterator::<K>::new_spec(k);
    let glb1 = r1.1@;
    let glb2 = r2.1@;
    assert(({
        let (id, glb) = r1;
        &&& id@ == self_@[k]
        &&& self_.lows.greatest_lower_bound_spec(KeyIterator::new_spec(k), glb@)
        &&& id@.valid_physical_address()
    }) && ({
        let (id, glb) = r2;
        &&& id@ == self_@[k]
        &&& self_.lows.greatest_lower_bound_spec(KeyIterator::new_spec(k), glb@)
        &&& id@.valid_physical_address()
    }) ==> det_get_internal_equal(r1, r2)) by {
        K::cmp_properties();
        K::zero_properties();
        if self_.lows.greatest_lower_bound_spec(iter, glb1)
            && self_.lows.greatest_lower_bound_spec(iter, glb2)
        {
            assert(!iter.is_end_spec());
            assert(glb1.k.is_Some());
            assert(glb2.k.is_Some());
            let k1 = glb1.k.get_Some_0();
            let k2 = glb2.k.get_Some_0();
            assert(self_.lows@.contains_key(k1));
            assert(self_.lows@.contains_key(k2));
            if glb1 != glb2 {
                assert(k1 != k2);
                let hi1 = choose|hi: KeyIterator<K>|
                    #[trigger] self_.lows.gap(glb1, hi)
                        && #[trigger] KeyIterator::between(glb1, iter, hi);
                let hi2 = choose|hi: KeyIterator<K>|
                    #[trigger] self_.lows.gap(glb2, hi)
                        && #[trigger] KeyIterator::between(glb2, iter, hi);
                assert(self_.lows.gap(glb1, hi1));
                assert(KeyIterator::between(glb1, iter, hi1));
                assert(self_.lows.gap(glb2, hi2));
                assert(KeyIterator::between(glb2, iter, hi2));
                if k1.cmp_spec(k2).lt() {
                    assert(glb1.lt_spec(KeyIterator::new_spec(k2)));
                    assert(KeyIterator::new_spec(k2).lt_spec(hi1));
                    assert(!self_.lows@.contains_key(*KeyIterator::<K>::new_spec(k2).get()));
                    assert(false);
                } else {
                    assert(k2.cmp_spec(k1).lt());
                    assert(glb2.lt_spec(KeyIterator::new_spec(k1)));
                    assert(KeyIterator::new_spec(k1).lt_spec(hi2));
                    assert(!self_.lows@.contains_key(*KeyIterator::<K>::new_spec(k1).get()));
                    assert(false);
                }
            }
            assert(glb1 == glb2);
            assert((r1.1)@ == (r2.1)@);
            assert(r1.0@ == r2.0@);
        }
    };
